o-1500530855697-b586d89ba3ee?w=800&q=80","location":"한라산 아침 시작","atmosphere":"맑고 상쾌한 산길","alt":"한라산 어승생악 산책로"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","location":"현무암 해안 절벽","atmosphere":"남쪽 바다의 강한 인상","alt":"대포 주상절리 해안"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","location":"숲길과 폭포 구간","atmosphere":"시원하고 차분한 분위기","alt":"천제연폭포 숲길"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=800&q=80","location":"오설록 차밭","atmosphere":"여유로운 그린 티 무드","alt":"오설록 티뮤지엄과 차밭"},{"id":6,"type":"video","src":"https://images.unsplash.com/photo-1493558103817-58b2924bce98?w=800&q=80","location":"애월 해안 마무리","atmosphere":"카페와 바다 전망","alt":"애월 카페거리 바다 풍경"}],"itineraryStops":[{"number":1,"time":"09:00","duration":"70분","name":"한라산 어승생악","category":"짧은 한라산 트레일","description":"하루는 한라산에서 시작합니다. 공기가 비교적 선선하고 체력이 남아 있는 오전에 어승생악을 먼저 걷는 것이 가장 자연스럽습니다. 코스 길이는 짧지만 한라산 특유의 숲길과 오름 풍경을 느낄 수 있어, 하루 전체에 산의 시작점을 분명하게 만들어 줍니다.","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","highlights":["짧지만 만족도가 높은 한라산 입문 코스","계단과 오르막이 있는 산책형 트레일","맑은 날에는 탁 트인 조망 기대 가능","하루의 첫 정차지로 집중도를 끌어올리기 좋음"],"timeUsed":["입구 도착 및 간단한 코스 안내","왕복 트레일과 주요 포인트 설명","하산 후 정리 및 다음 정차지 이동 준비"],"whyOnRoute":"하루 초반에 넣어야 체력 부담이 가장 적고, 이후 해안과 폭포 구간이 더 편안하게 느껴집니다.","visitBasics":{"hours":"05:00 입산 시작 / 계절별 입산 제한 시간 적용","closed":"기상 악화 시 통제 가능","admission":"무료","walking":"보통 이상"},"convenience":{"restroom":"입구 인근","parking":"가능"},"smartNotes":{"photo":"정상부보다 오르는 중간 구간에서 숲과 하늘이 함께 잡히는 사진이 더 좋습니다.","facilities":"산행형 정차지라 편의시설은 단순한 편입니다.","tip":"짧은 코스여도 계단이 많아 미끄럽지 않은 신발이 좋습니다."}},{"number":2,"time":"10:50","duration":"40분","name":"대포 주상절리","category":"현무암 해안 절벽","description":"한라산 구간 뒤에는 곧바로 바다 풍경이 열립니다. 대포 주상절리는 제주를 대표하는 화산 해안 경관 중 하나로, 기둥 모양의 현무암 절벽과 파도가 만나는 장면이 인상적입니다. 오전 산길과 강한 대비를 이루며 하루의 첫 해안 하이라이트가 됩니다.","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","highlights":["제주를 대표하는 주상절리 해안 풍경","파도와 절벽이 만드는 강한 시각적 대비","짧은 시간에도 만족도가 높은 대표 포인트","한라산 이후 화산 지형의 흐름을 이어주기 좋음"],"timeUsed":["도착 후 동선과 포토 포인트 안내","전망 구간 산책과 해안 감상","짧은 자유 시간 후 이동"],"whyOnRoute":"산에서 시작한 화산의 이야기를 해안 절벽으로 자연스럽게 연결해 줍니다.","visitBasics":{"hours":"09:00-18:00","closed":"없음","admission":"성인 2,000원 / 청소년 1,000원","walking":"쉬움"},"convenience":{"restroom":"입구 구역","parking":"가능"},"smartNotes":{"photo":"정면보다 사선 방향으로 절벽과 바다를 함께 담는 구도가 더 좋습니다.","facilities":"입구 쪽 편의시설은 무난한 편입니다.","tip":"바람이 강한 날에는 체감온도가 빨리 떨어질 수 있습니다."}},{"number":3,"time":"11:50","duration":"60분","name":"점심","category":"한낮 리셋 구간","description":"점심은 오전의 산과 해안 구간 뒤에서 하루의 리듬을 한 번 정리해 주는 시간입니다. 단순한 식사 시간이 아니라, 이후 천제연과 오설록, 애월까지 이어지는 후반부를 더 여유롭게 즐길 수 있게 만들어 주는 리셋 포인트입니다.","image":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","highlights":["오전 동선 뒤 체력을 정리하기 좋은 타이밍","남부 구간과 서부 구간을 자연스럽게 이어주는 중간 축","연령대가 섞인 팀에도 리듬이 편안함","후반부 분위기를 차분하게 이어가기 좋음"],"timeUsed":["식당 도착 및 자리 안내","식사와 짧은 휴식","후반 일정 출발 준비"],"whyOnRoute":"오전의 노출감 있는 코스를 지나고 나서 점심을 넣어야 후반부가 훨씬 부드럽게 이어집니다.","visitBasics":{"hours":"식당 운영시간 기준","closed":"업체별 상이","admission":"포함 또는 개별 결제","walking":"최소"},"convenience":{"restroom":"식당 내 시설","parking":"가능"},"smartNotes":{"photo":"음식 사진을 남기고 싶다면 제주 향토 메뉴가 가장 보기 좋습니다.","facilities":"가장 편하게 쉬기 좋은 정차 구간입니다.","tip":"이 구간에서 너무 급하게 움직이기보다 충분히 쉬는 편이 후반 만족도가 높습니다."}},{"number":4,"time":"13:00","duration":"50분","name":"천제연폭포","category":"폭포와 숲길 산책","description":"주상절리의 탁 트인 해안 뒤에는 천제연폭포가 보다 시원하고 차분한 분위기를 만들어 줍니다. 숲길, 다리, 폭포 전망 포인트가 어우러져서 후반부의 첫 장면을 부드럽게 열어 주며, 차밭과 애월로 넘어가기 전 경관의 결을 한 번 바꿔 줍니다.","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","highlights":["숲길과 폭포 전망이 함께 있는 대표 코스","주상절리 뒤에 이어지면 분위기 전환이 좋음","그늘 구간이 있어 한낮에도 상대적으로 걷기 편함","후반부 동선을 더 부드럽게 만들어 주는 정차지"],"timeUsed":["입구 도착 및 동선 안내","주요 전망 포인트 이동과 설명","사진 촬영 후 집결 및 이동"],"whyOnRoute":"강한 해안 풍경 뒤에 숲과 폭포를 넣으면 하루의 분위기가 훨씬 입체적으로 느껴집니다.","visitBasics":{"hours":"09:00-17:50","closed":"없음","admission":"성인 2,500원 / 청소년 1,350원","walking":"보통"},"convenience":{"restroom":"입구 구역","parking":"가능"},"smartNotes":{"photo":"폭포만 가까이 담기보다 다리와 숲을 함께 넣으면 더 분위기 있게 나옵니다.","facilities":"계단과 습한 구간이 있어 천천히 걷는 편이 좋습니다.","tip":"비 온 뒤에는 노면이 미끄러울 수 있어 발걸음을 서두르지 않는 것이 좋습니다."}},{"number":5,"time":"14:20","duration":"60분","name":"오설록 티뮤지엄","category":"차밭과 뮤지엄 정차","description":"천제연폭포 뒤에는 오설록이 하루의 분위기를 한층 부드럽게 바꿔 줍니다. 티뮤지엄, 기념품 숍, 차밭 풍경이 함께 있어 자연 관광에 라이프스타일 감각을 더해 주며, 마지막 애월로 넘어가기 전 템포를 편안하게 낮춰 줍니다.","image":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=800&q=80","highlights":["제주 서부를 대표하는 차밭 풍경","뮤지엄과 쇼핑, 사진 포인트를 함께 즐기기 좋음","후반부 분위기를 차분하게 전환해 줌","애월 전 마지막 완급 조절 구간으로 적합"],"timeUsed":["도착 후 자유 동선 안내","뮤지엄·숍·차밭 주변 관람","재집결 후 애월 이동"],"whyOnRoute":"폭포 산책 뒤에 오설록을 넣으면 후반부가 지나치게 힘들어지지 않고 자연스럽게 느슨해집니다.","visitBasics":{"hours":"09:00-18:00","closed":"없음","admission":"무료","walking":"쉬움"},"convenience":{"restroom":"관내 시설","parking":"가능"},"smartNotes":{"photo":"차밭은 정면보다 사선 구도에서 깊이감이 더 잘 살아납니다.","facilities":"카페와 매장, 화장실 등 편의성이 좋은 편입니다.","tip":"후반부 피로도가 쌓였을 때 가장 편하게 쉬어가기 좋은 정차지입니다."}},{"number":6,"time":"15:50","duration":"60분","name":"애월 카페거리","category":"카페 해안 마무리","description":"애월은 하루를 가볍게 마무리하기에 좋은 마지막 정차지입니다. 산 공기, 현무암 절벽, 폭포 숲길, 차밭 풍경을 지나온 뒤라서, 바다 전망과 카페 데크, 여유로운 해안 분위기가 하루 전체를 부드럽게 정리해 줍니다.","image":"https://images.unsplash.com/photo-1493558103817-58b2924bce98?w=800&q=80","highlights":["제주 서북부를 대표하는 카페 해안 분위기","바다 전망과 자유 시간이 잘 어울리는 마무리 포인트","복잡한 활동 없이 가볍게 즐기기 좋음","하루 전체를 여유롭게 마감해 주는 라이프스타일형 정차지"],"timeUsed":["대표 구간 도착 및 자유 동선 안내","카페 또는 해안 산책 자유 시간","집결 후 복귀 이동"],"whyOnRoute":"마지막을 애월로 마무리하면 하루가 또 다른 도보 코스가 아닌 여유로운 해안 무드로 끝납니다.","visitBasics":{"hours":"상점·카페별 상이","closed":"매장별 상이","admission":"자유 이용","walking":"쉬움"},"convenience":{"restroom":"카페 이용 시 가능","parking":"구역별 상이"},"smartNotes":{"photo":"카페만 단독으로 담기보다 바다와 함께 담는 구도가 더 좋습니다.","facilities":"개별 매장에 따라 차이가 있으므로 자유 시간이 핵심입니다.","tip":"노을 시간대와 겹치면 분위기가 훨씬 좋아질 수 있습니다."}}],"routeFlowStops":[{"id":"01","name":"어승생악","theme":"한라산"},{"id":"02","name":"주상절리","theme":"해안"},{"id":"03","name":"점심","theme":"리셋"},{"id":"04","name":"천제연","theme":"폭포"},{"id":"05","name":"오설록","theme":"차밭"},{"id":"06","name":"애월","theme":"카페 해안"}],"routePhases":[{"label":"오전","range":"1-2","theme":"한라산에서 해안까지","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"정오","range":"3-4","theme":"점심 & 폭포","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"마무리","range":"5-6","theme":"차밭 & 애월","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"이 일정의 흐름","subtitle":"한라산에서 시작해 해안, 점심, 폭포, 차밭을 지나 애월 바다로 마무리합니다. 09:00부터 17:30까지."},"whyTourWorks":{"bestFor":["첫 제주 여행자, 커플","성인 가족 여행","자연·차밭·여유로운 마무리를 함께 원하는 여행자","활동적인 시니어"],"lessIdeal":["계단이나 짧은 오르막을 피하고 싶은 분","유모차 위주 팀","아주 어린 아이 동반"],"routeLogicSections":[{"title":"동선과 리듬","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"한라산을 먼저, 체력이 남아 있을 때","detail":"어승생악은 짧지만 계단과 오르막이 있어 하루 초반에 배치하는 편이 가장 편안합니다."},{"label":"한낮에 점심, 흐름을 한 번 정리","detail":"점심이 오전의 노출감 있는 구간과 후반의 차분한 구간 사이에서 리듬을 깔끔하게 끊어 줍니다."},{"label":"오설록 뒤에는 가벼운 애월 마무리","detail":"차밭 구간으로 템포를 낮춘 뒤 애월로 끝나기 때문에 후반부가 무리 없이 풀립니다."}]},{"title":"루트 구성","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"산에서 시작해 바다로 확장","detail":"한라산에서 시작하면 고도감 있는 풍경이 먼저 잡히고, 이후 주상절리에서 바다가 강하게 열립니다."},{"label":"폭포 뒤 차밭으로 완급 조절","detail":"천제연이 먼저 하루를 시원하게 식혀 주고, 오설록이 후반부를 더 부드럽고 편안하게 이어 줍니다."},{"label":"마지막은 애월 카페 해안","detail":"또 다른 강한 도보 코스 대신 애월로 마무리해 하루 전체를 가볍게 정리합니다."}]},{"title":"상황이 바뀔 때","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"한라산 날씨 변수","detail":"어승생악은 급격한 날씨 변화나 탐방 통제의 영향을 받을 수 있습니다."},{"label":"해안 바람","detail":"주상절리와 애월은 내륙 구간보다 바람의 영향을 더 크게 느낄 수 있습니다."},{"label":"걷기 균형","detail":"대부분의 여행자에게 무리는 크지 않지만, 어승생악과 천제연에서는 계단과 짧은 오르막을 고려해야 합니다."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"픽업 & 샌딩","preview":"제주시권 호텔 로비 픽업","content":["08:20-08:50 사이 호텔 로비에서 픽업","17:50-18:20경 복귀 샌딩","요청 시 공항 픽업 가능","정확한 픽업 시간은 전날 저녁 안내"]},{"id":"walking","title":"도보 & 지형","preview":"전반적으로 보통, 대부분 무리 없이 가능","content":["전체 도보량: 정차지 전체 합산 약 4.5-5.5km","어승생악: 짧은 오르막과 계단이 많은 편","주상절리: 해안 전망 위주의 쉬운 동선","천제연: 숲길, 계단, 젖은 노면이 있을 수 있음","오설록·애월: 비교적 가볍고 자유롭게 조절 가능","미끄럽지 않은 편한 신발 권장"]},{"id":"weather","title":"날씨 & 통제 시 대응","preview":"대부분의 날씨에서 진행, 상황에 따라 조정","content":["가벼운 비: 정상 진행","강한 비 또는 탐방 통제: 어승생악 구간이 축소·조정될 수 있음","강풍: 주상절리 또는 애월 도보 시간이 줄어들 수 있음","후반부 날씨가 좋지 않을 때: 오설록 비중이 더 커질 수 있음","현장 통제 시: 대체 정차지로 조정될 수 있음"]},{"id":"wear","title":"복장 & 준비물","preview":"편한 신발, 겹쳐 입을 옷, 가벼운 겉옷","content":["접지력 있는 운동화 또는 워킹화","산과 해안의 온도 차에 대비한 레이어드 복장","바람막이 겸용 가벼운 겉옷","모자와 선크림","물병"]},{"id":"included","title":"포함 / 불포함","preview":"가이드, 차량, 픽업, 입장료 포함","variant":"included","content":["전문 영어 가이드","프라이빗 또는 소그룹 차량","제주시권 호텔 픽업/샌딩","전 입장료","생수","점심 식사(식당에서 직접 결제)","개인 쇼핑","매너팁"]}],"practicalWeatherStatic":{"today":{"temp":"11°","label":"오늘 · 맑음"},"tomorrow":{"temp":"18°/13°","label":"내일 · 이슬비"}},"seasonalVariations":[{"name":"봄","icon":"flower","description":"유채와 신록이 해안 풍경을 더 선명하게 만듭니다.","tag":"봄꽃 시즌","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"여름","icon":"sun","description":"해가 길고 녹음이 짙어 풍경이 더 생생합니다.","tag":"긴 일조시간","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"가을","icon":"leaf","description":"하늘이 맑고 시야가 좋아 조망 만족도가 높습니다.","tag":"전망 좋은 계절","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"겨울","icon":"snow","description":"동선이 한적해지고 차분한 분위기를 느끼기 좋습니다.","tag":"조용한 무드","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"check-circle","title":"제주 현지 운영","description":"제주 라이선스 가이드","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"서남부 동선 최적화","description":"서남부 흐름에 맞춘 루트","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"소규모 진행","description":"최대 8명","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"예약 즉시","title":"즉시 예약 확인","detail":"일정 요약이 포함된 예약 확인 안내"},{"timing":"12시간 전","title":"12시간 전 리마인드","detail":"날씨와 변동 사항 안내"},{"timing":"전날 저녁","title":"최종 픽업 안내","detail":"정확한 픽업 시간과 기사 연락처 안내"},{"timing":"투어 당일 아침","title":"당일 루트 노트","detail":"당일 컨디션에 따른 아침 브리핑"},{"timing":"투어 중","title":"정차지별 안내","detail":"각 장소에서 실시간 가이드 정보 제공"},{"timing":"투어 후","title":"투어 후 안내","detail":"후속 추천과 마무리 지원"}],"staticQuestions":[{"id":"first-time","question":"제주 첫 여행자에게도 괜찮은 코스인가요?","answer":"네. 한라산 풍경, 대표 화산 해안, 폭포 산책, 차밭 분위기, 그리고 애월의 여유로운 마무리를 하루에 균형 있게 담은 코스입니다."},{"id":"walking","question":"걷기 난이도가 많이 높은가요?","answer":"전체적으로는 무리가 큰 편은 아닙니다. 가장 활동적인 구간은 어승생악이며, 길이는 짧지만 계단이 많습니다. 나머지 구간은 대부분 여행자에게 보통 수준입니다."},{"id":"rain","question":"비가 와도 투어가 진행되나요?","answer":"네. 비가 오는 날에도 진행 가능하지만, 어승생악과 해안 노출 구간은 현장 상황에 따라 일부 축소되거나 조정될 수 있습니다."},{"id":"parents","question":"부모님과 함께 가도 괜찮을까요?","answer":"네. 전반적으로 성인 가족이 함께 즐기기 좋은 일정입니다. 다만 계단과 짧은 오르막은 감안하는 편이 좋습니다."},{"id":"children","question":"아이와 함께 참여해도 되나요?","answer":"네. 짧은 산책과 하루 일정에 무리가 없는 8세 이상 아이에게 더 잘 맞는 편입니다."},{"id":"order","question":"정차 순서가 바뀔 수도 있나요?","answer":"네. 산 날씨, 바람, 교통, 현장 혼잡도에 따라 특히 어승생악과 해안 구간 순서는 일부 조정될 수 있습니다."},{"id":"lunch","question":"점심 식사가 포함되나요?","answer":"상품 구성에 따라 다릅니다. 일정상 점심 시간은 포함되어 있지만, 식사 포함 여부는 예약하신 요금 조건을 확인해 주세요."},{"id":"why-eoseungsaengak","question":"왜 어승생악부터 시작하나요?","answer":"한라산 분위기를 하루의 시작에 담으면서도, 전체 일정이 본격 산행처럼 무거워지지 않도록 잡아 주기 때문입니다."},{"id":"why-jusangjeolli","question":"왜 한라산 다음에 주상절리를 가나요?","answer":"산의 화산 지형에서 시작해 제주를 대표하는 현무암 해안으로 흐름을 자연스럽게 이어 주기 때문입니다."},{"id":"why-osulloc","question":"왜 오설록 다음에 애월로 마무리하나요?","answer":"오설록에서 한 번 템포를 부드럽게 낮춘 뒤 애월로 넘어가야 후반부가 급하지 않고 자연스럽게 마무리됩니다."},{"id":"later-structure","question":"후반부를 이렇게 구성한 이유가 있나요?","answer":"점심과 천제연이 오전의 강한 구간 뒤 리듬을 부드럽게 정리해 주고, 오설록이 차밭 무드로 완급을 조절한 뒤 애월이 가볍게 하루를 닫아 주기 때문입니다."}],"guestReviews":[{"id":1,"author":"Sarah M.","avatar":"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&q=80","location":"싱가포르","date":"2024년 3월","rating":5,"title":"제주 서남부를 정말 균형 있게 본 하루였어요","text":"전체 동선이 정말 잘 짜여 있었어요. 한라산으로 시작하니 하루가 훨씬 살아났고, 그 뒤에 본 주상절리는 더 인상적으로 느껴졌습니다. 특히 오설록 다음에 애월로 이어지는 흐름이 무척 자연스러웠어요.","helpful":24,"verified":true,"tripType":"커플","photos":["https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400&q=80"]},{"id":2,"author":"James K.","avatar":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&q=80","location":"홍콩","date":"2024년 3월","rating":5,"title":"마무리가 특히 좋았던 서남부 코스","text":"한국에서 여러 투어를 해봤는데, 이 코스는 순서가 특히 좋았습니다. 가이드가 한라산, 주상절리, 천제연의 리듬을 아주 잘 잡아줬고, 오설록에서 애월로 이어지는 마무리 덕분에 피곤하기보다 균형 잡힌 하루처럼 느껴졌어요.","helpful":18,"verified":true,"tripType":"가족","photos":[]},{"id":3,"author":"Yuki T.","avatar":"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&q=80","location":"도쿄","date":"2024년 2월","rating":4,"title":"마지막 애월 구간이 특히 마음에 들었어요","text":"전체적으로 만족도가 높았습니다. 어승생악은 생각보다 시작점으로 훨씬 좋았고, 애월 전에 오설록이 들어간 것도 정말 좋았어요. 별점 4개를 준 이유는 애월에서 시간이 조금만 더 있었으면 했기 때문인데, 일정상 제약은 이해됩니다.","helpful":12,"verified":true,"tripType":"혼자 여행","photos":["https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=400&q=80"]},{"id":4,"author":"Michael R.","avatar":"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&q=80","location":"시드니","date":"2024년 2월","rating":5,"title":"생각보다 훨씬 다채로운 하루였습니다","text":"풍경을 기대하고 갔는데 설명까지 좋아서 더 만족스러웠습니다. 가이드가 한라산, 현무암 절벽, 폭포, 차밭, 애월 해안을 하나의 이야기처럼 자연스럽게 연결해 줬고, 소그룹이라 이동과 전환도 훨씬 편했어요.","helpful":31,"verified":true,"tripType":"친구","photos":[]}],"reviewsSummary":{"averageRating":4.8,"totalReviews":127,"ratingDistribution":[{"stars":5,"count":98,"percentage":77},{"stars":4,"count":21,"percentage":17},{"stars":3,"count":6,"percentage":5},{"stars":2,"count":1,"percentage":1},{"stars":1,"count":1,"percentage":1}],"highlights":[{"label":"풍경","count":89},{"label":"가이드","count":76},{"label":"동선","count":54},{"label":"사진 포인트","count":48}]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"58","currency":"USD","per":"인"}},"sectionUi":{"atAGlanceTitle":"한눈에 보기","atAGlanceSubtitle":"풍경, 도보 부담, 전체적인 맞춤도를 빠르게 살펴보세요.","atmosphereTitle":"코스의 분위기","atmosphereSubtitle":"세부 일정 전에, 하루가 어떻게 느껴지는지부터 보세요.","itineraryTitle":"정차지별 하루 일정","itinerarySubtitle":"각 정차는 자연스럽게 이어집니다. 펼쳐서 상세 정보를 확인하세요.","dayFlowStopsPrefix":"정차","stopHighlightsHeading":"하이라이트","stopTimeUsedHeading":"시간 활용","stopVisitBasicsHeading":"방문 정보","stopVisitHoursLabel":"운영 시간","stopVisitAdmissionLabel":"입장","stopVisitWalkingLabel":"도보","stopVisitClosedLabel":"휴무","stopSmartNotesHeading":"현장 팁","stopSmartNotesPhotoPrefix":"사진:","stopSmartNotesTipPrefix":"팁:","fitTitle":"이 투어가 잘 맞는 이유","fitSubtitle":"이 템포가 어울리는 분과 하루를 어떻게 배치하는지 안내합니다.","fitBestForLabel":"이렇게 추천","fitLessIdealLabel":"덜 맞을 수 있는 분","fitFamiliesPrefix":"가족:","fitFamiliesText":"8세 이상 권장. 짧은 등산로와 계단 구간에 적응할 수 있는 분께 적합합니다.","fitSeniorsPrefix":"시니어:","fitSeniorsText":"어승생악·천제연 구간은 속도를 낮추면 대부분의 여행객이 참여하기 좋습니다.","fitRouteLogicTitle":"코스 설계","fitRouteLogicSubtitle":"템포, 순서, 정차 시간, 하루가 이렇게 흘러가는 이유","practicalTitle":"실용 정보","practicalSubtitle":"픽업, 도보, 날씨, 준비물, 포함 사항.","seasonalTitle":"계절별 느낌","seasonalSubtitle":"이 코스가 사계절에 어떻게 다가오는지.","bookingSupportTitle":"예약과 지원","bookingSupportSubtitle":"예약 전·투어 중·이후에 무엇을 기대할 수 있는지.","bookingAfterTitle":"예약 이후","bookingAfterSubtitle":"투어 전·중·후 받게 되는 지원","faqTitle":"자주 묻는 질문","faqSubtitle":"결정에 도움이 되는 핵심 질문들.","faqShowFewer":"접기","faqMoreQuestionsTemplate":"추가 질문 {count}개","faqFooterTitle":"예약 전 더 궁금하신가요?","faqFooterLink":"언제든 메시지 주세요","reviewsTitle":"게스트 후기","reviewsSubtitle":"이 경험에 대해 여행자들이 말하는 것.","reviewsBasedOnTemplate":"총 {total}개 후기 기준","reviewsGuestsMention":"후기에 자주 등장하는 키워드","reviewsShowFewerReviews":"후기 접기","reviewsShowAllTemplate":"전체 {count}개 후기 보기","reviewsVerified":"인증됨","reviewsReadMore":"더 읽기","reviewsShowLess":"접기","reviewsHelpfulTemplate":"도움됨 ({count})","reviewsCtaTitle":"이 투어 다녀오셨나요?","reviewsCtaSubtitle":"다른 여행자에게 경험을 공유해 주세요.","reviewsWriteReview":"후기 작성"}}'::jsonb
ON CONFLICT (slug, locale) DO UPDATE SET
  product_id = EXCLUDED.product_id,
  is_published = EXCLUDED.is_published,
  sort_order = EXCLUDED.sort_order,
  tour_id = EXCLUDED.tour_id,
  title = EXCLUDED.title,
  subtitle = EXCLUDED.subtitle,
  region_label = EXCLUDED.region_label,
  duration_label = EXCLUDED.duration_label,
  stops_count = EXCLUDED.stops_count,
  rating_avg = EXCLUDED.rating_avg,
  review_count = EXCLUDED.review_count,
  badges = EXCLUDED.badges,
  hero_image_url = EXCLUDED.hero_image_url,
  thumbnail_url = EXCLUDED.thumbnail_url,
  card_short_description = EXCLUDED.card_short_description,
  seo_title = EXCLUDED.seo_title,
  meta_description = EXCLUDED.meta_description,
  headline_line_1 = EXCLUDED.headline_line_1,
  headline_line_2 = EXCLUDED.headline_line_2,
  price_amount_label = EXCLUDED.price_amount_label,
  price_currency = EXCLUDED.price_currency,
  price_per = EXCLUDED.price_per,
  detail_payload = EXCLUDED.detail_payload,
  updated_at = NOW();

COMMIT;

SELECT slug, locale, is_published, product_id, left(meta_description, 60) AS meta_preview
FROM public.tour_product_pages
WHERE slug = 'southwest-hallasan-osulloc-aewol' AND locale = 'ko';
